DROP DATABASE IF EXISTS warehouse_management;
CREATE DATABASE warehouse_management CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci;
USE warehouse_management;
CREATE TABLE UserRoles(RoleID INT AUTO_INCREMENT PRIMARY KEY,RoleName VARCHAR(50) NOT NULL UNIQUE,Description VARCHAR(255));
CREATE TABLE Employees(EmployeeID INT AUTO_INCREMENT PRIMARY KEY,FullName VARCHAR(150) NOT NULL,Position VARCHAR(80) NOT NULL,Phone VARCHAR(40),Email VARCHAR(120),HireDate DATE NOT NULL,IsActive BOOLEAN NOT NULL DEFAULT TRUE);
CREATE TABLE Users(UserID INT AUTO_INCREMENT PRIMARY KEY,FullName VARCHAR(150) NOT NULL,Login VARCHAR(80) NOT NULL UNIQUE,Password VARCHAR(120) NOT NULL,Email VARCHAR(120),Phone VARCHAR(40),RoleID INT NOT NULL,EmployeeID INT NULL,CreatedAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,IsBlocked BOOLEAN NOT NULL DEFAULT FALSE,CONSTRAINT fk_users_roles FOREIGN KEY(RoleID) REFERENCES UserRoles(RoleID),CONSTRAINT fk_users_employees FOREIGN KEY(EmployeeID) REFERENCES Employees(EmployeeID));
CREATE TABLE Categories(CategoryID INT AUTO_INCREMENT PRIMARY KEY,CategoryName VARCHAR(100) NOT NULL UNIQUE,Description VARCHAR(255));
CREATE TABLE Units(UnitID INT AUTO_INCREMENT PRIMARY KEY,UnitName VARCHAR(80) NOT NULL UNIQUE,ShortName VARCHAR(20) NOT NULL UNIQUE);
CREATE TABLE Suppliers(SupplierID INT AUTO_INCREMENT PRIMARY KEY,SupplierName VARCHAR(150) NOT NULL,ContactPerson VARCHAR(120),Phone VARCHAR(40),Email VARCHAR(120),Address VARCHAR(255));
CREATE TABLE Clients(ClientID INT AUTO_INCREMENT PRIMARY KEY,ClientName VARCHAR(150) NOT NULL,ContactPerson VARCHAR(120),Phone VARCHAR(40),Email VARCHAR(120),Address VARCHAR(255));
CREATE TABLE Warehouses(WarehouseID INT AUTO_INCREMENT PRIMARY KEY,WarehouseName VARCHAR(120) NOT NULL,Address VARCHAR(255) NOT NULL);
CREATE TABLE StorageZones(ZoneID INT AUTO_INCREMENT PRIMARY KEY,WarehouseID INT NOT NULL,ZoneName VARCHAR(80) NOT NULL,TemperatureMode VARCHAR(60),CONSTRAINT fk_zones_warehouse FOREIGN KEY(WarehouseID) REFERENCES Warehouses(WarehouseID),UNIQUE(WarehouseID,ZoneName));
CREATE TABLE StorageLocations(LocationID INT AUTO_INCREMENT PRIMARY KEY,ZoneID INT NOT NULL,LocationCode VARCHAR(40) NOT NULL UNIQUE,MaxWeight DECIMAL(10,2) NOT NULL CHECK(MaxWeight>0),CONSTRAINT fk_locations_zone FOREIGN KEY(ZoneID) REFERENCES StorageZones(ZoneID));
CREATE TABLE Products(ProductID INT AUTO_INCREMENT PRIMARY KEY,Sku VARCHAR(60) NOT NULL UNIQUE,ProductName VARCHAR(180) NOT NULL,Description VARCHAR(500),PurchasePrice DECIMAL(12,2) NOT NULL CHECK(PurchasePrice>=0),SalePrice DECIMAL(12,2) NOT NULL CHECK(SalePrice>=0),CategoryID INT NOT NULL,UnitID INT NOT NULL,SupplierID INT NOT NULL,MinStock INT NOT NULL DEFAULT 0 CHECK(MinStock>=0),IsActive BOOLEAN NOT NULL DEFAULT TRUE,CONSTRAINT fk_products_categories FOREIGN KEY(CategoryID) REFERENCES Categories(CategoryID),CONSTRAINT fk_products_units FOREIGN KEY(UnitID) REFERENCES Units(UnitID),CONSTRAINT fk_products_suppliers FOREIGN KEY(SupplierID) REFERENCES Suppliers(SupplierID));
CREATE TABLE StockBalances(BalanceID INT AUTO_INCREMENT PRIMARY KEY,ProductID INT NOT NULL,LocationID INT NOT NULL,Quantity INT NOT NULL DEFAULT 0 CHECK(Quantity>=0),UpdatedAt DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT fk_balances_products FOREIGN KEY(ProductID) REFERENCES Products(ProductID),CONSTRAINT fk_balances_locations FOREIGN KEY(LocationID) REFERENCES StorageLocations(LocationID),UNIQUE(ProductID,LocationID));
CREATE TABLE Receipts(ReceiptID INT AUTO_INCREMENT PRIMARY KEY,ReceiptNumber VARCHAR(40) NOT NULL UNIQUE,SupplierID INT NOT NULL,EmployeeID INT NOT NULL,ReceiptDate DATETIME NOT NULL,Comment VARCHAR(255),CONSTRAINT fk_receipts_suppliers FOREIGN KEY(SupplierID) REFERENCES Suppliers(SupplierID),CONSTRAINT fk_receipts_employees FOREIGN KEY(EmployeeID) REFERENCES Employees(EmployeeID));
CREATE TABLE ReceiptItems(ReceiptItemID INT AUTO_INCREMENT PRIMARY KEY,ReceiptID INT NOT NULL,ProductID INT NOT NULL,LocationID INT NOT NULL,Quantity INT NOT NULL CHECK(Quantity>0),UnitPrice DECIMAL(12,2) NOT NULL CHECK(UnitPrice>=0),CONSTRAINT fk_receipt_items_receipts FOREIGN KEY(ReceiptID) REFERENCES Receipts(ReceiptID) ON DELETE CASCADE,CONSTRAINT fk_receipt_items_products FOREIGN KEY(ProductID) REFERENCES Products(ProductID),CONSTRAINT fk_receipt_items_locations FOREIGN KEY(LocationID) REFERENCES StorageLocations(LocationID));
CREATE TABLE Shipments(ShipmentID INT AUTO_INCREMENT PRIMARY KEY,ShipmentNumber VARCHAR(40) NOT NULL UNIQUE,ClientID INT NOT NULL,EmployeeID INT NOT NULL,ShipmentDate DATETIME NOT NULL,Comment VARCHAR(255),CONSTRAINT fk_shipments_clients FOREIGN KEY(ClientID) REFERENCES Clients(ClientID),CONSTRAINT fk_shipments_employees FOREIGN KEY(EmployeeID) REFERENCES Employees(EmployeeID));
CREATE TABLE ShipmentItems(ShipmentItemID INT AUTO_INCREMENT PRIMARY KEY,ShipmentID INT NOT NULL,ProductID INT NOT NULL,LocationID INT NOT NULL,Quantity INT NOT NULL CHECK(Quantity>0),UnitPrice DECIMAL(12,2) NOT NULL CHECK(UnitPrice>=0),CONSTRAINT fk_shipment_items_shipments FOREIGN KEY(ShipmentID) REFERENCES Shipments(ShipmentID) ON DELETE CASCADE,CONSTRAINT fk_shipment_items_products FOREIGN KEY(ProductID) REFERENCES Products(ProductID),CONSTRAINT fk_shipment_items_locations FOREIGN KEY(LocationID) REFERENCES StorageLocations(LocationID));
CREATE TABLE Inventories(InventoryID INT AUTO_INCREMENT PRIMARY KEY,InventoryNumber VARCHAR(40) NOT NULL UNIQUE,WarehouseID INT NOT NULL,EmployeeID INT NOT NULL,InventoryDate DATETIME NOT NULL,Status VARCHAR(40) NOT NULL,CONSTRAINT fk_inventories_warehouses FOREIGN KEY(WarehouseID) REFERENCES Warehouses(WarehouseID),CONSTRAINT fk_inventories_employees FOREIGN KEY(EmployeeID) REFERENCES Employees(EmployeeID));
CREATE TABLE InventoryResults(ResultID INT AUTO_INCREMENT PRIMARY KEY,InventoryID INT NOT NULL,BalanceID INT NOT NULL,ExpectedQuantity INT NOT NULL CHECK(ExpectedQuantity>=0),ActualQuantity INT NOT NULL CHECK(ActualQuantity>=0),Difference INT NOT NULL,Comment VARCHAR(255),CONSTRAINT fk_inventory_results_inventories FOREIGN KEY(InventoryID) REFERENCES Inventories(InventoryID) ON DELETE CASCADE,CONSTRAINT fk_inventory_results_balances FOREIGN KEY(BalanceID) REFERENCES StockBalances(BalanceID));
CREATE TABLE ActionLogs(LogID INT AUTO_INCREMENT PRIMARY KEY,UserID INT NULL,ActionDate DATETIME NOT NULL DEFAULT CURRENT_TIMESTAMP,ActionType VARCHAR(60) NOT NULL,EntityName VARCHAR(80),EntityID INT NULL,Details VARCHAR(500),CONSTRAINT fk_logs_users FOREIGN KEY(UserID) REFERENCES Users(UserID));
